import{_ as e,o as i,c as a,ao as d}from"./chunks/framework.DGf-9kxS.js";const _=JSON.parse('{"title":"Implementation map","description":"","frontmatter":{},"headers":[],"relativePath":"diagnostics-and-validation/implementation-map.md","filePath":"diagnostics-and-validation/implementation-map.md","lastUpdated":null}'),l={name:"diagnostics-and-validation/implementation-map.md"};function n(r,t,o,s,g,c){return i(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="Implementation-map" tabindex="-1">Implementation map <a class="header-anchor" href="#Implementation-map" aria-label="Permalink to &quot;Implementation map {#Implementation-map}&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Status — Implemented</p><p>Mirrors drmTMB&#39;s <a href="https://itchyshin.github.io/drmTMB/articles/implementation-map.html" target="_blank" rel="noreferrer">Implementation map</a>. Where the <strong>source map</strong> lists <em>files</em> and the <strong>model map</strong> lists <em>capability status</em>, this page maps each <strong>modelling feature → the numerical method that fits it → the fitter entry point</strong> in the source. All entries are taken from <code>src/</code>.</p></div><p>Every fit ultimately minimises a negative log-likelihood by L-BFGS with ForwardDiff gradients; the rows below differ in <strong>how the random-effect / correlation integral is handled</strong>.</p><h2 id="The-verified-engine-phylogenetic-q4-PLSM" tabindex="-1">The verified engine (phylogenetic q=4 PLSM) <a class="header-anchor" href="#The-verified-engine-phylogenetic-q4-PLSM" aria-label="Permalink to &quot;The verified engine (phylogenetic q=4 PLSM) {#The-verified-engine-phylogenetic-q4-PLSM}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Feature</th><th style="text-align:right;">Method</th><th style="text-align:right;">Entry point</th></tr></thead><tbody><tr><td style="text-align:right;">q=4 phylogenetic bivariate location–scale</td><td style="text-align:right;">sparse <strong>augmented-state Laplace</strong> + exact <strong>O(p)</strong> gradient (implicit-function, Takahashi selected inverse — never forms dense Σ)</td><td style="text-align:right;"><code>fit_q4_sparse_tmb</code></td></tr></tbody></table><h2 id="Gaussian-location–scale" tabindex="-1">Gaussian location–scale <a class="header-anchor" href="#Gaussian-location–scale" aria-label="Permalink to &quot;Gaussian location–scale {#Gaussian-location–scale}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Feature</th><th style="text-align:right;">Method</th><th style="text-align:right;">Entry point</th></tr></thead><tbody><tr><td style="text-align:right;">fixed effects</td><td style="text-align:right;">direct ML</td><td style="text-align:right;"><code>_fit_fixed_gaussian</code></td></tr><tr><td style="text-align:right;">random intercept <code>(1|g)</code></td><td style="text-align:right;">closed-form marginal (Woodbury / determinant lemma)</td><td style="text-align:right;"><code>_fit_ranef_gaussian</code></td></tr><tr><td style="text-align:right;">correlated <code>(1+x|g)</code></td><td style="text-align:right;">per-group 2×2 block capacitance, log-Cholesky Σ</td><td style="text-align:right;"><code>_fit_correlated_ranef_gaussian</code></td></tr><tr><td style="text-align:right;">crossed <code>(1|g)+(1|h)</code></td><td style="text-align:right;">whitened-Woodbury dense capacitance <code>M = I + Z̃ᵀD⁻¹Z̃</code></td><td style="text-align:right;"><code>_fit_multi_ranef_gaussian</code></td></tr><tr><td style="text-align:right;">scale RE <code>sigma ~ (1|g)</code></td><td style="text-align:right;">32-node Gauss–Hermite marginal on log σ</td><td style="text-align:right;"><code>_fit_sigma_ranef_gaussian</code></td></tr><tr><td style="text-align:right;"><code>relmat</code> / <code>animal</code> / <code>phylo</code></td><td style="text-align:right;">structured GLS (determinant lemma + Woodbury, known K)</td><td style="text-align:right;"><code>_fit_structured_gaussian</code></td></tr><tr><td style="text-align:right;"><code>spatial(1|site)</code></td><td style="text-align:right;">exponential kernel <code>K(ρ)=exp(-d/ρ)</code>, range estimated</td><td style="text-align:right;"><code>_fit_spatial_gaussian</code></td></tr><tr><td style="text-align:right;">meta-analysis <code>meta_V(v)</code></td><td style="text-align:right;">known-variance GLS + heterogeneity τ</td><td style="text-align:right;"><code>_fit_meta_gaussian</code></td></tr></tbody></table><h2 id="Non-Gaussian-families" tabindex="-1">Non-Gaussian families <a class="header-anchor" href="#Non-Gaussian-families" aria-label="Permalink to &quot;Non-Gaussian families {#Non-Gaussian-families}&quot;">​</a></h2><p>The shared scheme: an explicit, AD-safe log-likelihood; random intercepts by Gauss–Hermite quadrature (<code>b = √2 σ_b z</code>); correlated <code>(1+x|g)</code> by a 2-D GHQ tensor grid; crossed intercepts by the sparse-Laplace spine (<code>sparse_laplace_glmm.jl</code>).</p><table tabindex="0"><thead><tr><th style="text-align:right;">Family</th><th style="text-align:right;">Fixed</th><th style="text-align:right;"><code>(1|g)</code></th><th style="text-align:right;"><code>(1+x|g)</code></th><th style="text-align:right;">crossed</th><th style="text-align:right;">other</th></tr></thead><tbody><tr><td style="text-align:right;">Student-t</td><td style="text-align:right;"><code>_fit_student</code></td><td style="text-align:right;"><code>_fit_student_ranef</code></td><td style="text-align:right;"><code>_fit_student_corr_ranef</code></td><td style="text-align:right;">—</td><td style="text-align:right;">—</td></tr><tr><td style="text-align:right;">Poisson</td><td style="text-align:right;"><code>_fit_poisson</code></td><td style="text-align:right;"><code>_fit_poisson_ranef</code></td><td style="text-align:right;"><code>_fit_poisson_corr_ranef</code></td><td style="text-align:right;"><code>_fit_poisson_crossed_laplace</code></td><td style="text-align:right;"><code>zi</code> / <code>hu</code>: <code>_fit_poisson_zi</code> / <code>_fit_poisson_hu</code></td></tr><tr><td style="text-align:right;">NB2</td><td style="text-align:right;"><code>_fit_negbin2</code></td><td style="text-align:right;"><code>_fit_negbin2_ranef</code></td><td style="text-align:right;"><code>_fit_negbin2_corr_ranef</code></td><td style="text-align:right;"><code>_fit_nb2_crossed_laplace</code></td><td style="text-align:right;"><code>zi</code> / <code>hu</code>: <code>_fit_negbin2_zi</code> / <code>_fit_negbin2_hu</code>; truncated: <code>_fit_truncated_negbin2</code></td></tr><tr><td style="text-align:right;">Gamma</td><td style="text-align:right;"><code>_fit_gamma</code></td><td style="text-align:right;"><code>_fit_gamma_ranef</code></td><td style="text-align:right;"><code>_fit_gamma_corr_ranef</code></td><td style="text-align:right;"><code>_fit_gamma_crossed_laplace</code></td><td style="text-align:right;">—</td></tr><tr><td style="text-align:right;">Beta</td><td style="text-align:right;"><code>_fit_beta</code></td><td style="text-align:right;"><code>_fit_beta_ranef</code></td><td style="text-align:right;"><code>_fit_beta_corr_ranef</code></td><td style="text-align:right;"><code>_fit_beta_crossed_laplace</code></td><td style="text-align:right;">—</td></tr><tr><td style="text-align:right;">Binomial</td><td style="text-align:right;"><code>_fit_binomial</code></td><td style="text-align:right;"><code>_fit_binomial_ranef</code></td><td style="text-align:right;">—</td><td style="text-align:right;"><code>_fit_binomial_crossed_laplace</code></td><td style="text-align:right;">—</td></tr><tr><td style="text-align:right;">Beta-binomial</td><td style="text-align:right;"><code>_fit_betabinomial</code></td><td style="text-align:right;"><code>_fit_betabinomial_ranef</code></td><td style="text-align:right;"><code>_fit_betabinomial_corr_ranef</code></td><td style="text-align:right;">—</td><td style="text-align:right;"><code>cbind(s, f)</code> response</td></tr><tr><td style="text-align:right;">LogNormal</td><td style="text-align:right;"><code>_fit_lognormal</code></td><td style="text-align:right;"><code>_fit_lognormal_ranef</code></td><td style="text-align:right;"><code>_fit_lognormal_corr_ranef</code></td><td style="text-align:right;">—</td><td style="text-align:right;">—</td></tr><tr><td style="text-align:right;">Zero-one-inflated Beta</td><td style="text-align:right;"><code>_fit_zeroonebeta</code></td><td style="text-align:right;">—</td><td style="text-align:right;">—</td><td style="text-align:right;">—</td><td style="text-align:right;">closed <code>[0,1]</code></td></tr><tr><td style="text-align:right;">Tweedie</td><td style="text-align:right;"><code>_fit_tweedie</code></td><td style="text-align:right;">—</td><td style="text-align:right;">—</td><td style="text-align:right;">—</td><td style="text-align:right;">compound Poisson–Gamma</td></tr><tr><td style="text-align:right;">Cumulative-logit</td><td style="text-align:right;"><code>_fit_cumulative</code></td><td style="text-align:right;">—</td><td style="text-align:right;">—</td><td style="text-align:right;">—</td><td style="text-align:right;">ordered categorical</td></tr></tbody></table><h2 id="Shared-spine" tabindex="-1">Shared spine <a class="header-anchor" href="#Shared-spine" aria-label="Permalink to &quot;Shared spine {#Shared-spine}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Concern</th><th style="text-align:right;">Method</th><th style="text-align:right;">Entry point</th></tr></thead><tbody><tr><td style="text-align:right;">crossed / structured non-Gaussian RE</td><td style="text-align:right;">sparse-Laplace marginal + exact nuisance gradient</td><td style="text-align:right;"><code>sparse_laplace_glmm.jl</code> (<code>_fit_crossed_mean_laplace</code>, <code>…_nuisance</code>)</td></tr><tr><td style="text-align:right;">selected inverse for the O(p) correction</td><td style="text-align:right;">Takahashi recursion on the sparse Cholesky</td><td style="text-align:right;"><code>takahashi_selinv</code></td></tr><tr><td style="text-align:right;">inference</td><td style="text-align:right;">Wald (observed information), profile (LR inversion), parametric bootstrap</td><td style="text-align:right;"><code>inference.jl</code></td></tr></tbody></table><p>Function names are internal (the public verbs are <code>drm</code> / <code>bf</code> and the accessors); this map is for orientation when reading or extending the source.</p>',13)])])}const y=e(l,[["render",n]]);export{_ as __pageData,y as default};
